INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68028022e3c98b0941765d7e', '已经很久没有遇到各个方面都没有雷点的酒店了。入住了粤韵客房（金卡升级的），房间很新很舒服。

服务：从前台到礼宾到客房还有餐厅都体验很好，虽然酒店有高达约850间的客房，但是依旧一切都井然有序，对于定位豪华或者奢华的五星级酒店来说并不是简单的事情。

设施：红棉客房往上就蛮大面积了，很舒服。酒店的几家餐厅轮着吃一吃就很舒服了，满意。

吃完还可以去花园里看看锦鲤。', '["https://dimg04.c-ctrip.com/images/0236l12000al8bsfd11EE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235812000al7n0q7405D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231r12000al8krsy5F99_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234j12000al88gxkCB30_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000al7ilwg9C88_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236g12000al87zg46227_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232712000al7q3qe44B6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233712000al8lxokD4DC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000al8hfr75CA0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-04', '红棉双床套房', '套房', '朋友出游', 183, 0, 54, 8, '["整体满意度","房间设施","餐饮设施"]'::jsonb, '整体满意度', '房间设施', '餐饮设施'),
('68028022e3c98b0941765d7f', '还不错，酒店服务很好。下次还会入住，希望保持
服务：很好
环境：周边在装修
卫生：很细致
设施：老旧。房间重新装修了，但是房间比较小呢', '["https://dimg04.c-ctrip.com/images/0235a12000bf0zr8p619A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234212000bf11b3mFB95_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230g12000bf0vx0d4C3B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-15', '花园大床房', '大床房', '商务出差', 67, 0, 28, 6, '["整体满意度","客房服务","卫生状况"]'::jsonb, '整体满意度', '客房服务', '卫生状况'),
('68028022e3c98b0941765d80', '酒店位置好，交通方便，吃方便，周边点德都，陶陶居，广州酒家等，都很近。大堂高大尚，有五星级酒店的派头，客房嘛，毕竟是老酒店了！
服务挺好的！
入住时，花园饭店的商会在搞活动。', '["https://dimg04.c-ctrip.com/images/0232s12000arj0wha62BB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235p12000arj26t26232_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000arj8dbc004E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-03-12', '花园双床房', '双床房', '家庭亲子', 87, 0, 42, 7, '["交通便利性","周边配套","整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度'),
('68028022e3c98b0941765d81', '非常棒的一次体验，入住酒店还送了点心和水果?早餐在酒店的旋转餐厅，小孩子很喜欢??前台的小姐姐（Savanna小圆）服务很专业贴心，虽然国庆期间入住等待时间长，但是等待入住的时间有乐队表演，还给小孩送了小点心和花花，非常棒的一次体验?推荐??', '["https://dimg04.c-ctrip.com/images/0232t12000cc21mvoFA68_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000cc20ve87DB5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000cc1xqhq58FD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-05', '盼酷小黄鸭亲子主题套房', '主题房', '家庭亲子', 121, 0, 4, 8, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('6802802de3c98b0941765d82', '酒店前台接待态度很好??，能满足客人的需求，酒店的后花园非常nice,房间卫生干净整洁，床品也非常舒服，酒店有各种美食，能满足各地客人的需求，口感非常好，这是一次非常棒的入住体验，非常满意????', '["https://dimg04.c-ctrip.com/images/0231e12000aqlvqdi4A37_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000aqm8l043230_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-05', '红棉大床套房', '套房', '商务出差', 98, 0, 7, 6, '["前台服务","卫生状况","餐饮设施"]'::jsonb, '前台服务', '卫生状况', '餐饮设施'),
('6802802de3c98b0941765d83', '房间很nice 前台Billy也很热情 专业 好评 
下次还会再来的 还有很哇塞的瀑布餐厅', '["https://dimg04.c-ctrip.com/images/023112224wdqwjso11E61_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w2234ch42mz9c2131_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023142215gadqhonk75E3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-09', '红棉大床套房', '套房', '情侣出游', 45, 0, 15, 5, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('6802802de3c98b0941765d84', '设施：就在地铁边上，交通很方便，停车免费，还可以充电呢。床超级舒服，睡了一个大懒觉。
卫生：完全符合白金五星的要求，安心使用。
服务：必须为前台的Elvis，Mikey点赞，他们的用心服务让我以后都必须选择花园，真让我开心满意。', '["https://dimg04.c-ctrip.com/images/0231d12000arok098FCAE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235u12000arodshj38B3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232i12000arogaj682B9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-13', '花园大床房', '大床房', '朋友出游', 114, 0, 4, 8, '["交通便利性","房间设施","前台服务"]'::jsonb, '交通便利性', '房间设施', '前台服务'),
('6802802de3c98b0941765d85', '酒店位置很好，门口就是5号线淘金站，3、8、4号都很方便，酒店不愧是老牌五星酒店，各方面都很不错，房间略小，主要洗漱和卫生间空间比较局促。最令我们印象深刻的是客服服务小李，因为前一天大热天去了长隆，喝了很多水，房间里留了好几个矿泉水空瓶，他不但多给我们补了两瓶水，还手写了一张便条给我们，让人感觉太贴心了。', '["https://dimg04.c-ctrip.com/images/0230c12000f2mzwpa8E45_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m12000f2mv48t7021_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-08-10', '花园双床房', '双床房', '家庭亲子', 153, 0, 1, 9, '["交通便利性","客房服务","房间设施"]'::jsonb, '交通便利性', '客房服务', '房间设施'),
('6802802de3c98b0941765d86', '服务热情，特别是前台viria的服务让我们有宾至如归的感觉。地理位置好，门口就是地铁口，出行方便。酒店景观美，下次还会选择入住', '["https://dimg04.c-ctrip.com/images/0235u12000e6sm9c990BC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233u12000e6ssen7412C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000e6smql41AC1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f12000e6snx2249DF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000e6ssgumFD37_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235a12000e6susi0FE19_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-27', '花园大床房', '大床房', '其他', 63, 0, 7, 7, '["前台服务","交通便利性","景观/朝向"]'::jsonb, '前台服务', '交通便利性', '景观/朝向'),
('6802802de3c98b0941765d87', '这次出行前做了好久的选择最后选择了？花园酒店，因为想让妈妈和孩子体验岭南文化，在入住前看到一些不好的评价心里也有点忐忑，可当我们从进入酒店开始就感受到各种温馨。前台看到我带着两个娃给我升级了新翻新的套房，办理入住后还有专人帮忙带上房间，入住了两天酒店的卫生和服务都非常到位，可以用一句成语宾至如归概括，六月份去广州一定会再次预定花园酒店，真心推荐！
设施：新装修的房间，设施齐全，卫生间的防臭做得非常完美！
卫生：干净整洁
环境：舒适
服务：yyds', '["https://dimg04.c-ctrip.com/images/0235k12000aqriydu0FD9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235b12000aqriiwk1ABD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000aqriwv4D537_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000aqrijzg7A26_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000aqrikla1443_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230k12000aqrh0es828A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231n12000aqrj73u7962_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000aqrod0t4797_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231812000aqriq22FFC4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-06', '花园双床房', '双床房', '家庭亲子', 225, 0, 4, 8, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('6802802de3c98b0941765d88', '老酒店了，值得体验', '["https://dimg04.c-ctrip.com/images/0234e12000c3z8lmiA59A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-09-11', '红棉大床套房', '套房', '家庭亲子', 9, 0, 3, 3, '["整体满意度","性价比"]'::jsonb, '整体满意度', '性价比', NULL),
('6802802de3c98b0941765d89', '闹市区地铁口，环境非常好隔音很棒，有私家小花园，瀑布水榭亭台楼阁健身房，游泳池，中西餐厅各取所需！同时传播岭南文化，房间布置很有特色', '["https://dimg04.c-ctrip.com/images/0231412000avoowcs4D70_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000avouvfb619B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000avod0ss9439_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000avop5sj9EA2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-07', '花园大床房', '大床房', '家庭亲子', 66, 0, 3, 8, '["公共设施","安静程度","周边配套"]'::jsonb, '公共设施', '安静程度', '周边配套'),
('6802802de3c98b0941765d8a', '广州人的情怀，老牌五星酒店但依然焕发着粤韵活力', '["https://dimg04.c-ctrip.com/images/0234h12000bhs68pmD1DF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-25', '花园大床房', '大床房', '朋友出游', 23, 0, 2, 6, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('6802802de3c98b0941765d8b', 'kristy服务很好，酒店环境很好', '["https://dimg04.c-ctrip.com/images/0230k12000blqz15dD5E2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-08', '花园大床房', '大床房', '家庭亲子', 17, 0, 9, 4, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028038e3c98b0941765d8c', '总体来说，花园酒店的设施和服务都挺好的，床品都很舒服。不过，我们订的时候有送博物馆的票，但是在办入住的时候，前台忘记给我们了，直到check out时候才给，大家自己记得要吧，没有限期，下次再用吧', '["https://dimg04.c-ctrip.com/images/0233m12000aovqpr9617B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-19', '花园大床房', '大床房', '商务出差', 98, 0, 5, 6, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('68028038e3c98b0941765d8d', '推荐给长隆玩过之后，想留一天的时间给老广州感受岭南文化的朋友。

        酒店在繁华的淘金区，长隆玩过之后打车40分钟左右就到酒店了。因为酒店开业时间早，期望并不高。一进入酒店大堂，我们一家三口就感慨这是此行最满意的酒店了。

         携程白金卡会员订房后可以自动成为岭客汇金卡享受行政酒廊待遇。特别值得体验的是行政酒廊的早餐。推荐户外位置用餐，在瀑布和花园旁享用自助+单点美食，轻松拥有度假的松弛感。不用担心户外位置叫不到服务人员的情况，carrie，Danil, lisa几位工作人员会随时check用餐情况。家有嗦粉爱好者的朋友们，推荐尝试一下米粉+牛腩+云吞的组合，家中乐宝整碗汤全部喝完。', '["https://dimg04.c-ctrip.com/images/0235b12000anz7lw4CC49_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235w12000anz6p865710_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233812000anza9xlB01A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236i12000anz6bgjDD31_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234s12000anyzu8u36E0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235712000anz0epbBBAB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-13', '花园双床房', '双床房', '家庭亲子', 308, 1, 1, 9, '["餐饮设施","整体满意度","交通便利性"]'::jsonb, '餐饮设施', '整体满意度', '交通便利性'),
('68028038e3c98b0941765d8e', '酒店设施齐全，房间也很干净整洁，保洁大姐很热情，每次见面都会问有什么需要；前台小姐姐办理入住，讲解很细致；酒店里有自己的花园，风景很好，每天都会带孩子去院子里转转；早餐也特别咱，种类丰富。值得推荐', '["https://dimg04.c-ctrip.com/images/0231s12000aqr7bc00C0C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000aqr6glc93A7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230c12000aqr4ndi2F2F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-06', '花园双床房', '双床房', '家庭亲子', 98, 0, 3, 8, '["整体满意度","房间设施","卫生状况"]'::jsonb, '整体满意度', '房间设施', '卫生状况'),
('68028038e3c98b0941765d8f', '集文化，美食，园林景观于一体的酒店。酒店内有博物馆和多家餐厅。日料，味道很不错。早餐，下午茶和欢乐时光都在锦里吧用餐。菜品非常棒，服务也周到。特别是锦里吧的印度籍女生Carre更是贴心。非常棒的体验。', '["https://dimg04.c-ctrip.com/images/0236j12000bi4g7dpF697_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000bi4mdbpDE2C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000bi48g7j449A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000bi4fi08C5C1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d12000bi4jmkp60CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235812000bi49uqjF0FB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231c12000bi4jxv23D82_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235112000bi4jpt2ED47_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000bi48mplC746_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-26', '花园双床房', '双床房', '家庭亲子', 100, 0, 23, 8, '["餐饮设施","整体满意度","前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务'),
('68028038e3c98b0941765d90', '非常有历史文化感的一个老牌国宾馆似的酒店。首先地理位置真的对于刚来广州的朋友很友好，出门就是地铁淘金站，周围吃饭 打车 都很方便。
老牌酒店的管理和服务接待都做的很好，一进门就有礼宾司的先生帮我们推行李，排队中也有接待人员引导，跟办理入住时候的小姐姐更是亲切惬意的对话，如沐春风。
房间帮我们升级到套房，虽然有些古旧，毕竟老酒店了，但是总的来说性价比超级高了。没有过分超出付出的要求来讲我觉得下次来广州我还会入住。
大堂富丽堂皇中有浓浓岭南风情，主要米其林餐厅好几个都在此酒店，早早预定的我们简直每天下楼就是幸福的感觉～', '["https://dimg04.c-ctrip.com/images/0230712000aorymu402D7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237312000aorzb5fF050_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000aoruz0wC355_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000aos66488DE9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000aoryzmzB292_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236j12000aos6atk090D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000aos5uxqD621_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231612000aos12y26CC3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-18', '花园大床房', '大床房', '其他', 260, 0, 17, 9, '["交通便利性","前台服务","性价比"]'::jsonb, '交通便利性', '前台服务', '性价比'),
('68028038e3c98b0941765d91', '入住广州花园酒店，整体体验非常不错。
酒店的环境优雅，房间宽敞明亮，地理位置位于广州的老中心，环市路核心地段，新装修后的红棉套房现代而不失温馨。房间内的设施齐全，床铺舒适，完全能让人在一天的奔波后能拥有一个安静、舒适的休息空间。
酒店的餐饮选择也很丰富，早餐种类多样，满足了不同客人的口味需求。总的来说，装修后的广州花园酒店绝对是一家值得信赖的酒店，无论是商务出行还是休闲旅游，都能让客人享受到高品质的服务和舒适的住宿环境。特别感谢前台的Betty，工作效率高，态度和蔼可亲，脸上总是洋溢着温暖的笑容。即使在忙碌的时候，她也能迅速办理入住和退房手续，让客人感受到酒店的专业服务。', '["https://dimg04.c-ctrip.com/images/0232u12000ja2lwwcF42E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234712000ja29yuf81AD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231g12000ja4682b2260_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231r12000ja34qhg203F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u12000ja3tsz315BD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235712000ja2ii2i2787_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233b12000ja3r7h345F6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000ja4depb29FC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236t12000ja4es198251_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-24', '花园大床房', '大床房', '商务出差', 289, 0, 11, 9, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68028038e3c98b0941765d92', '第一次去广州玩选到这个酒店真的很不错，酒店的风景很美池塘里有很多鲤鱼很好看，还有一个很有特色的瀑布餐厅，早上起来看着瀑布吃着早餐很不错，而且交通也很方便去哪都很近，酒店拍照也很美，房间也住的很舒服，住的那个房间可以看见瀑布和一半的广州塔非常好', '["https://dimg04.c-ctrip.com/images/0202q12000anz4wk5BAE5_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0233i12000anyyh40C4C9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231f12000anyy5saBE35_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235k12000anyzghrF409_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000anys464B8A7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236r12000anywbb702E9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236o12000anyzmyfC207_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-13', '红棉大床套房', '套房', '情侣出游', 121, 0, 3, 8, '["景观/朝向","餐饮设施","交通便利性"]'::jsonb, '景观/朝向', '餐饮设施', '交通便利性'),
('68028038e3c98b0941765d93', '每次来广州都想住这家酒店，这次终于订到房间了，过年的原因，办理入住的宾客很多，酒店的服务很细心，还给等待的宾客送了饮料鲜花，整个大堂布置很有年味，后面的花园环境很优美，闹中取静。房间给人感觉有点压抑，走廊和房间的内空都比较矮，入住时安排的房间在五楼，窗户不能打开，而且外面就是平台，窗外没什么景观，而且沙发上还残留长头发，给人第一感觉不是很好，协调前台马上给换了六楼的一间，稍好一点，面盆的龙头是松的，晃晃悠悠，维修部及时修复，洗澡的细节不是很好，每次淋浴都要跨进浴缸，老年人可千万要当心不要摔倒。值得肯定的是酒店服务很到位很热情很专业！', '["https://dimg04.c-ctrip.com/images/0203512000ailm00s44E7_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0236n12000aili6bu6685_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234n12000ailj5dkE494_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000ailjq7sA7D5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000ailj9ce5774_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000aili33dED3C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000ailii3x4029_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000ailihvwCD21_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000ailixuy9A25_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231c12000ailitkl6EA3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-01-27', '城央绿意双床房', '双床房', '家庭亲子', 269, 1, 4, 8, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('68028038e3c98b0941765d95', '酒店卫生干净整洁，环境优雅！舒适！地理位置很好，设施齐全！', '["https://dimg04.c-ctrip.com/images/0236b12000bd5k2eaE332_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234j12000bd5fp17250C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235j12000bd5dv6yF1D8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000bd5ehsuD94C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237412000bd57n2c00E2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-06', '花园大床房', '大床房', '商务出差', 29, 0, 4, 5, '["卫生状况","整体满意度","周边配套"]'::jsonb, '卫生状况', '整体满意度', '周边配套'),
('68028043e3c98b0941765d96', '宝藏酒店！入住升级了房型 房间非常大！瀑布餐厅的环境非常好，还有免费的博物馆可以逛！周围也有很多商场 店铺 地铁就在旁边 非常方便', '["https://dimg04.c-ctrip.com/images/0230x12000aulk2me5A4B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000aulq1oh88D5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-04', '花园大床房', '大床房', '家庭亲子', 65, 0, 2, 8, '["交通便利性","周边配套","整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度'),
('68028043e3c98b0941765d97', '反正就是很不值
设施大概80年代的
到处有霉点，有物资
客服不积极
前台接待服务很差
明明提前联系好，确认好房型
结果还是弄错了房型，和订的不一样！
前台说没房间了，不能给我订的，what？这是我的错么？？？
门厅很好看，大气
房间就呵呵了', '["https://dimg04.c-ctrip.com/images/0234712000arggzmw72F6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231k12000anrm7i578FC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236v12000anrm7i31427_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1, 1, '2023-03-11', '城央绿意大床房', '大床房', '商务出差', 120, 4, 7, 7, '["前台服务","房间设施","性价比"]'::jsonb, '前台服务', '房间设施', '性价比'),
('68028043e3c98b0941765d98', '总体而言，我的广州花园酒店之行是一次非常满意的体验。酒店的优雅环境、舒适的客房、美味的餐饮以及前台Nicky等员工的优质服务，都让我的住宿体验变得难忘。我强烈推荐广州花园酒店给那些寻求高品质服务和舒适住宿的旅客。', '["https://dimg04.c-ctrip.com/images/0231l12000hch7hukB7F6_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231512000hch7zltB182_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0230g12000hch82xf359B_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-12-22', '花园大床房', '大床房', '朋友出游', 106, 0, 17, 7, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68028043e3c98b0941765d99', '酒店的位置非常优越，门口就有地铁，出行便利，酒店的餐厅环境优美，用餐时使人心情愉悦，服务人员也很负责到位。酒店房间设施一般，洗澡只能站在浴缸里，没有喷淋的独立空间，对于老人和儿童很不友好！没有数据线插孔，这个就很不方便，不足之处希望加以改变！', '["https://dimg04.c-ctrip.com/images/0234d12000anbrc1f4BAD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236a12000anbvtou6689_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234j12000anb63cd6E78_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231112000anbfhoh8586_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233e12000anb6keyAE52_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230c12000anb1kn196B7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-02-11', '花园双床房', '双床房', '家庭亲子', 121, 0, 6, 8, '["房间设施","交通便利性","餐饮设施"]'::jsonb, '房间设施', '交通便利性', '餐饮设施'),
('68028043e3c98b0941765d9a', '前台服务态度好，热情，g开头英文名字服务人员，很快帮我们办理了入住，还免费升级房间，赞！酒店环境不错，推荐来广州首选入住。', '["https://dimg04.c-ctrip.com/images/0233812000dyhc7yj66F8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000dyha6se6047_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232a12000dyh6qrz6526_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-11', '花园大床房', '大床房', '家庭亲子', 61, 0, 19, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028043e3c98b0941765d9b', '酒店服务很好，下车就有人帮拿行李，大堂大气，办理入住井然有序，我非周末节假日去的正好人不算多，亲子房很大，很干净小朋友超级开心，酒店真的有个花园，好多花花草草锦鲤，18米瀑布也是亮点', '["https://dimg04.c-ctrip.com/images/0231612000apcifcy12AC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b12000apc0l3eB132_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000apcfxrwE80D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000apbqzs52707_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-23', '大嘴猴亲子主题大床房', '主题房', '家庭亲子', 91, 0, 13, 8, '["整体满意度","前台服务","卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况'),
('68028043e3c98b0941765d9c', '房间比较满意，对前台工作人员B?tIIy也很满意，很感谢工作人员很热情', '["https://dimg04.c-ctrip.com/images/0231z12000c1ro0ne3DED_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-01', '红棉大床套房', '套房', '独自旅行', 35, 0, 3, 5, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68028043e3c98b0941765d9d', '酒店非常的不错，景色很美，设备很齐全！入住的时候看到有小孩，免费给酒店做了升级！前台Becity Charies态度非常的好！非常不错的体验。', '["https://dimg04.c-ctrip.com/images/0236i12000asomfopC89C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-21', '花园大床房', '大床房', '家庭亲子', 71, 0, 5, 7, '["整体满意度","前台服务","景观/朝向"]'::jsonb, '整体满意度', '前台服务', '景观/朝向'),
('68028043e3c98b0941765d9e', '总体体验非常棒的酒店，能感受到丰富的文化底蕴。前台的rivia小姐姐态度友善，脸上永远挂着笑容，耐心的讲解酒店入住的注意事项，还贴心的建议我们尽快去酒廊体验下午茶，替我们担心时间来不及。

酒店处处都是景，负责讲解25个打卡点的老师非常认真细致，让人觉得住在花园酒店根本不需要出门，酒店内的景点就足够你细细品味，博物馆也超出预期，有清晰的参观线索、丰富的藏品和精彩的说不完的背后故事。

两天一晚接近24小时的时间过得很快，我们基本打卡了酒店里所有的景点、餐厅、博物馆、健身房、泳池，这是一座近现代文化交融的酒店，你既能从很多细节中找寻到中国酒店业发展的记忆，也能不经意间感受到酒店努力拥抱现代化、不断创新紧跟时代的步伐，既能体会到成熟完善的硬件设施带给你的处处方便，也能享受到热情体贴的酒店工作人员展现出的人文关怀。这是一座你入住其他诸如万豪、希尔顿、洲际、凯悦等豪华酒店所无法体会到的独特感受，一份只属于广州花园酒店的特别记忆。', '["https://dimg04.c-ctrip.com/images/0234q12000c5zp0hfAF98_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233012000c5zrrfwCBDF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234512000c5zoo38AEDF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000c5zn38wB67E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-17', '红棉大床套房', '套房', '情侣出游', 416, 0, 1, 10, '["整体满意度","前台服务","公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施'),
('68028043e3c98b0941765d9f', '非常漂亮，感谢Tony给我们做了升房，非常满意的一次旅程', '["https://dimg04.c-ctrip.com/images/0236z2234bfiprpw0BEE7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z2234bfiprxluD16B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231r2224vc5jplvkDA10_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h2224vc5jptldB643_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023522215f8sdnhv5E8F8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-06', '花园双床房', '双床房', '情侣出游', 28, 0, 2, 4, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028052e3c98b0941765da0', '一进酒店大堂就被震惊了，礼宾部的小哥哥都好热情，服务非常好。酒店的花园超级漂亮，小朋友每天都要去打卡～', '["https://dimg04.c-ctrip.com/images/0236l12000b1h2ped85BC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000b1gwczb44BC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232612000b1h3eua468E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233a12000b1gy72f15D2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000b1gv5xvC195_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236m12000b1gkvza9412_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-23', '花园大床房', '大床房', '家庭亲子', 51, 0, 12, 6, '["前台服务","公共设施"]'::jsonb, '前台服务', '公共设施', NULL),
('68028052e3c98b0941765da1', '让人印象深刻的一次行程。
本来趁着疫情放开，客流不大来广州。
预订了一个套房，三个人，前台的小姐姐还帮我卖做了升级，送了鲜花和宝格丽的礼物。
房间视野开阔，面对着白云山，楼下就是地铁站。
酒店的布局很有特色，院子中有个瀑布，营造了自然的氛围。
庭院小桥流水，曲径通幽，令人心旷神怡。', '["https://dimg04.c-ctrip.com/images/0232412000anu4chb214B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233412000anugjjg0448_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236q12000anudx3w4407_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235112000anucfmf1317_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236j12000ans2x242F87_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231s12000antco2iC909_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233b12000anu6o2s637F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232f12000anumlnqDD0F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233h12000ansi3987232_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-13', '红棉双床套房', '套房', '朋友出游', 141, 0, 34, 8, '["景观/朝向","交通便利性","前台服务"]'::jsonb, '景观/朝向', '交通便利性', '前台服务'),
('68028052e3c98b0941765da2', '第一次来广州，选择入住的花园酒店，酒店非常漂亮，因为是金卡会员，还给升级了房间，房间很漂亮，又大，晚上去了行政酒廊，体验感非常棒，Zoey,和NIKKI，对客服务热情周到细心，服务非常好，让我以及我的朋友很满意，她们二位的服务让我留下深刻印象。下次来一定还要住你们酒店。

3', '["https://dimg04.c-ctrip.com/images/0236g12000aln8fmp366E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000alnhffx3721_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000alnq34769BD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232o12000alnoun1E9EE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-05', '花园双床房', '双床房', '家庭亲子', 138, 0, 3, 8, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('68028052e3c98b0941765da3', '广州花园酒店的阳台玻璃应该擦擦了 房内射灯一闪一闪的 上洗手间就不能洗澡 洗澡就不能上洗手间（就一组推拉门）同样是免费的矿泉水看看万豪 洗澡间顶都掉皮了 早餐葱白还带着根 中国白金五星酒店 就只能看外表了', '["https://dimg04.c-ctrip.com/images/0230712000alo4ctw97DE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234f12000alnwjfdB796_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d12000alnbn3t60DE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236w12000alns6daC07E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234z12000alnyidw71F4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237212000alo44tr10D1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.7, 2, '2023-02-05', '花园双床房', '双床房', '家庭亲子', 102, 4, 12, 8, '["房间设施","卫生状况","餐饮设施"]'::jsonb, '房间设施', '卫生状况', '餐饮设施'),
('68028052e3c98b0941765da4', '酒店虽老一些，但是服务意识特别的好，前台办理入住的小姐姐很有耐心，也帮我们留了高楼层的房间。还送了花和小饼干。早餐特别丰富，整体还是很好的。', '["https://dimg04.c-ctrip.com/images/0231212000asf6qxb29CA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000asf0z9bE9CC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-19', '红棉大床套房', '套房', '商务出差', 70, 0, 4, 7, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68028052e3c98b0941765da5', '这个酒店入住给我们留下了非常不好的印象
不明白为什么会这样
希望管理层重视起来
1，checkin效率低，办理入住30分钟，大厅排队很长
2，2点入住，结果三点半，到酒店告诉我房间没有打扫好，只能先给一间，我们安排老人带孩子先休息，两个人疲惫的在附近转悠了一个半小时（五点）房间还没有打扫好，在我们的争取下给我们安排了顶层，结果房间在消防通道旁边，床很小，设施成旧，没有淋浴间，只有一个老式浴缸，很无语……
3，针对这些问题，酒店没有任何态度，只能说让我们等
携程客服积极的给我们处理了，但是还是有点失望??

客观的说，酒店位置挺好，旁边就是地铁，停车场也挺方便，酒店的花园应该是两点', '["https://dimg04.c-ctrip.com/images/0232q12000ak1cec416B0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236s12000ak1ahi471E6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236o12000ak12zl10BA3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000ak1cech9B94_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.5, 2, '2023-02-01', '花园双床房', '双床房', '家庭亲子', 293, 3, 21, 8, '["退房/入住效率","房间设施","前台服务"]'::jsonb, '退房/入住效率', '房间设施', '前台服务'),
('68028052e3c98b0941765da6', '第一晚订住的大床房有两个问题
1、下水道反味 比公共厕所还臭。第二天下午五点换房得以解决。
2、隔音差 隔壁房间孩子的嬉闹声一清二楚。
还好第二天换房得以解决，不然将是一次糟糕的旅程。
酒店亮点：
1、环境优美
2、周围较多老字号餐厅', '["https://dimg04.c-ctrip.com/images/0236z12000akdf4zt3EF3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000akdu4ma4476_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000akdkzmp83DD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000akdv4oy7AFB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3, 3, '2023-02-02', '花园大床房', '大床房', '情侣出游', 117, 1, 11, 7, '["房间设施","安静程度"]'::jsonb, '房间设施', '安静程度', NULL),
('68028052e3c98b0941765da7', '优点：服务非常好，不愧为广州老牌五星级的酒店。地理位置绝佳，门口就有地铁（5号线淘金站），对面就是广州酒家和白云宾馆，附近步行可到陶陶居，五号线坐五站珠江新城出来就是花城大道，看广州塔夜景的极佳位置。
不足：设施老化，毕竟上世纪八十年代的酒店，不过维护的还可以，也算卫生；早餐品种和质量感觉对不起这个价格和五星级酒店的身份，早餐质量感觉也就国内中档酒店比如亚朵的水平，而且空间很小，八点半后去基本需要排队等座。

整体感觉还是蛮好的，在广州五星酒店里价格相对亲民，应该还会再次选择花园酒店。

祝生意兴隆。', '["https://dimg04.c-ctrip.com/images/0235u12000alnwi28C0C4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233t12000aln24kvB928_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000alnty7y7F26_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-02-05', '花园大床房', '大床房', '家庭亲子', 253, 0, 2, 9, '["交通便利性","性价比","餐饮设施"]'::jsonb, '交通便利性', '性价比', '餐饮设施'),
('68028052e3c98b0941765da8', '预订了基础的房型，体验入住感一般。酒店地理位置很好，出行交通方便，门口就有地铁站，但对开车客人来说非常不方便，地面停车场每次进出都要去大堂输入车牌号，没人告知过，为此来回跑过两次，而且大堂输入车牌信息的位置经常没人等待很久。
另外这次和家人入住是两晚，第二晚时候突然想在酒店用早餐办理付费过后前台送了几包欢迎小饼干，这欢迎小饼干难道不该在我办理入住的时候送吗？？付完早餐钱想起来自己是岭客汇金卡，但是办理入住的时候并没有升级房型、早餐等服务，经过协商，付的早餐钱退给了我，会员的两次单早并成一次双早。不知道这会员权益是该自己讨还是前台关注的，体验感不是很好。
不过酒店的花园还有博物馆有时间还是推荐逛一逛的', '["https://dimg04.c-ctrip.com/images/0236p12000atjmpo24177_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230712000atjp7125973_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000atjo8226AE0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2023-03-28', '花园大床房', '大床房', '家庭亲子', 303, 1, 5, 8, '["交通便利性","前台服务","周边配套"]'::jsonb, '交通便利性', '前台服务', '周边配套'),
('68028052e3c98b0941765da9', '房间高度很日式有点压抑，服务很好KRISTT小姐姐主动帮助退房，旁边有很多好吃酒家，下次还会入住。', '["https://dimg04.c-ctrip.com/images/0230x12000b1p2uom0D85_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000b1phyg10ED5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233t12000b1p8dejFBDB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-24', '花园双床房', '双床房', '家庭亲子', 49, 0, 51, 7, '["前台服务","周边配套","整体满意度"]'::jsonb, '前台服务', '周边配套', '整体满意度'),
('6802805ee3c98b0941765daa', '第一次住花园酒店，升级了行政套房．房间很大有书房健身房．洗手间也有二间，太棒了，看夜景也很宽阔，卫生干净，服务周到！花园里的风景好看，还有瀑布', '["https://dimg04.c-ctrip.com/images/0230u12000b7d81wo7CDB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000b7dc72b41B5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000b7d1ln95D3E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-12', '花园双床房', '双床房', '朋友出游', 71, 0, 11, 8, '["房间设施","整体满意度","卫生状况"]'::jsonb, '房间设施', '整体满意度', '卫生状况'),
('6802805ee3c98b0941765dab', '设施：大气的厅堂，快速的电梯，整体硬件不错。房间比较温馨，略小，尤其是卫生间和淋浴间太小了点。
卫生：不错，尤其是9楼打扫的人员总是反复确认要帮忙打扫，假期人多还能这样很赞！
服务：有好有坏，办理入住等待的人很多，有贴心的发小发夹和汽水，缓解等待的着急情绪。办理入住的Ken服务很好，因为是中秋还送了月饼。
不好的地方，下车没有人帮取行李，因为独自带孩子有两个箱子，招呼了门童才不情愿的拿了一下；瀑布餐厅煎蛋的大叔态度不友好，说话阴阳怪气！
早餐：看评论这个酒店是餐饮著称，但遗憾的是早餐很普通，分别在一楼和30楼吃了，没有什么特色，可选的也是有限，8点以后就要排队。早餐最大的亮点是到12点，可以不必太匆忙！
环境：非常好，毕竟叫花园酒店！', '["https://dimg04.c-ctrip.com/images/0235l12000cc5r5jj8D45_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234j12000cc5jyb8F0FA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-10-06', '城央绿意大床房', '大床房', '家庭亲子', 321, 0, 6, 9, '["前台服务","餐饮设施","房间设施"]'::jsonb, '前台服务', '餐饮设施', '房间设施'),
('6802805ee3c98b0941765dac', '一如继往的优秀，主要服务一流，工作人员礼貌客气。地段好性价比高。外国客人很多，酒店代收了很多快递帮忙整理。', '["https://dimg04.c-ctrip.com/images/0236f4234bodg3f7431AA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-28', '花园大床房', '大床房', '商务出差', 53, 0, 54, 7, '["前台服务","性价比","交通便利性"]'::jsonb, '前台服务', '性价比', '交通便利性'),
('6802805ee3c98b0941765dad', '花园酒店声名在外，最早的合资五星级酒店，作为广州人的我，竟然到了2023年春节，才有机会感受她的风采!疫情过后复常神速，从上海回来特地选了她，结果上海话一路不绝于耳，不说地点还以为自己没有离开上海!
Doorman: 有分寸感的礼貌，很好。
Lobby: 很久没有看见这样热闹的节日氛围，喜欢。
Check in: 春节期间超长等待房间已是常态，没办法。
红棉大床房: 房间老旧面积颇大，听说装修排期中。
服务: 我的 Housekeeping 是整个行程的精华，超棒。
饮食: 荔湾亭失望/自助餐无感/酒吧这个烤蔬菜一流。
总结: I will be back! Thank you!', '["https://dimg04.c-ctrip.com/images/0232x12000asojozu10FB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234112000asoe5c9832A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234l12000ajiv7ww17CA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235j12000asogtwj523B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-03-21', '红棉大床套房', '套房', '其他', 293, 0, 7, 8, '["整体满意度","客房服务","房间设施"]'::jsonb, '整体满意度', '客房服务', '房间设施'),
('6802805ee3c98b0941765dae', '酒店交通出行方便，客房舒适，配套设施齐全，风景优美，中西美食俱全。特别是Carol 小姐很专业，善解人意，喜欢住这里，还会再来。', '["https://dimg04.c-ctrip.com/images/0231z12000cd1qo0f2AD1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000cd1qoql427F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-09', '花园双床房', '双床房', '朋友出游', 64, 0, 3, 6, '["交通便利性","整体满意度","餐饮设施"]'::jsonb, '交通便利性', '整体满意度', '餐饮设施'),
('6802805ee3c98b0941765daf', '每次和儿子去动物园都住这里，这次入住太差了，开房门后房间里面还有客户搞的自己马上退出来了，换另外一个房间又等半小时而且房间空气清新剂味道太重，五星级就这待遇，如果不是近动物园真心不选择。', '["https://dimg04.c-ctrip.com/images/0233g12000apaia7p85C5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000apage7mD3CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236z12000apa86y07F06_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231j12000apa7rmn6DC5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2023-02-22', '粤韵大床套房', '套房', '家庭亲子', 93, 0, 14, 7, '["退房/入住效率","客房服务","整体满意度"]'::jsonb, '退房/入住效率', '客房服务', '整体满意度'),
('6802805ee3c98b0941765db0', '在携程花1474元定了该酒店27日入住的64平米的粤韵1.3米双床套房，在前台登记入住时说房间没打扫出来，可以免费升级成行政套房，结果该套房又旧又破，沙发又脏又破，马桶老旧，灯好几盏不亮，这种也好意思叫升级房型？这种欺骗消费者的行为，不讲信誉的行为，发生老牌的五星级酒店，真是让心寒。再三协调要求换回原定房型，先是说没有了，晚上七点半再找到经理说，有房岀来，但打扫需要二个半小时，一直到了晚上十一点，孩子已经睡了，只有放弃换房。该酒店这种忽悠消费者，借节假日客房销售旺季，卖老旧客房的行为，让人就像吃了个苍蝇一样恶心。', '["https://dimg04.c-ctrip.com/images/0231k12000aj0zdm4C7D7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234y12000aj12ihb623E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000aj0x4dxBBD1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236g12000aj12roy1490_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233412000aj0yc6gADD4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234s12000aj133812B2D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 1, 1, '2023-01-28', '粤韵双床套房', '套房', '家庭亲子', 259, 15, 1, 9, '["房间设施","前台服务","整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度')
 ON CONFLICT (_id) DO NOTHING;
